import{_ as a,c as i,o as l,$ as o}from"./chunks/framework.ByJNblvT.js";const u=JSON.parse('{"title":"🏝️ 环境要求","description":"","frontmatter":{},"headers":[],"relativePath":"guide/environment.md","filePath":"guide/environment.md","lastUpdated":1774623019000}'),d={name:"guide/environment.md"};function n(r,e,t,c,s,p){return l(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="🏝️-环境要求" tabindex="-1">🏝️ 环境要求 <a class="header-anchor" href="#🏝️-环境要求" aria-label="Permalink to “🏝️ 环境要求”">​</a></h1><h2 id="推荐环境" tabindex="-1">推荐环境 <a class="header-anchor" href="#推荐环境" aria-label="Permalink to “推荐环境”">​</a></h2><p>推荐在现代浏览器中，配合 <code>npm</code> / <code>pnpm</code> / <code>yarn</code> / <code>bun</code> 等包管理工具使用。</p><p>如果你是在业务项目中接入，优先建议：</p><ul><li>使用 ESM 构建工具，如 Vite、Rspack、Webpack、Rollup 等</li><li>在客户端组件挂载后再初始化图表</li><li>通过包管理器安装，而不是直接依赖 CDN 脚本</li></ul><h2 id="浏览器支持" tabindex="-1">浏览器支持 <a class="header-anchor" href="#浏览器支持" aria-label="Permalink to “浏览器支持”">​</a></h2><p>图表基于 HTML5 Canvas 构建，需要运行在支持 Canvas 的浏览器上。如果需要运行在移动端，请使用现代 WebView 加载。</p><p>对于现代桌面浏览器和移动端浏览器，一般都可以直接运行；如果你的业务需要兼容较老环境，建议至少确认下面这些能力：</p><ul><li><code>Map</code></li><li><code>Intl</code></li><li><code>requestAnimationFrame</code></li><li>Canvas 相关 API</li></ul><p>其中 Canvas 相关 API 支持是必须的。<code>Map</code> ， <code>Intl</code> 和 <code>requestAnimationFrame</code> 是比较常见的兼容补齐项，如果缺失，自行补齐相关 polyfill。</p><h2 id="ssr-next-js-nuxt-注意事项" tabindex="-1">SSR / Next.js / Nuxt 注意事项 <a class="header-anchor" href="#ssr-next-js-nuxt-注意事项" aria-label="Permalink to “SSR / Next.js / Nuxt 注意事项”">​</a></h2><p>图表依赖 DOM 和 Canvas，因此不能在服务端渲染阶段直接初始化。</p><p>推荐做法：</p><ul><li>在组件挂载完成后，再执行 <code>init(...)</code></li><li>不要在模块顶层直接读取容器 DOM</li><li>如果页面是按需显示的，等容器真正可见后再初始化或主动调用 <code>resize(...)</code></li></ul><h2 id="容器尺寸与初始化时机" tabindex="-1">容器尺寸与初始化时机 <a class="header-anchor" href="#容器尺寸与初始化时机" aria-label="Permalink to “容器尺寸与初始化时机”">​</a></h2><p>图表会自动填充容器，因此容器本身必须有明确尺寸。</p><p>常见建议：</p><ul><li>容器需要有确定的高度</li><li>如果宽度来自父容器自适应，确保父级布局已稳定</li><li>如果容器初始是 <code>display: none</code> 或位于未激活的 tab 中，显示后建议调用一次 <code>resize(...)</code></li></ul><p>如果初始化后只能看到一条线，或图表区域高度异常，优先检查容器尺寸。</p><h2 id="高清屏与清晰度" tabindex="-1">高清屏与清晰度 <a class="header-anchor" href="#高清屏与清晰度" aria-label="Permalink to “高清屏与清晰度”">​</a></h2><p>在高分辨率屏幕上，如果你发现图表发虚，建议先检查页面是否对图表容器做了额外的 CSS 缩放。</p><p>推荐：</p><ul><li>避免对图表容器使用 <code>transform: scale(...)</code></li><li>避免在图表外层再套一层模糊缩放容器</li><li>尺寸变化后及时调用 <code>resize(...)</code></li></ul><h2 id="移动端-webview-注意事项" tabindex="-1">移动端 WebView 注意事项 <a class="header-anchor" href="#移动端-webview-注意事项" aria-label="Permalink to “移动端 WebView 注意事项”">​</a></h2><p>移动端使用时，建议优先在较新的 WebView 环境中运行。</p><p>接入时通常要注意：</p><ul><li>页面滚动和图表拖拽是否冲突</li><li>父容器是否拦截了触摸事件</li><li>键盘弹起、横竖屏切换后是否需要重新 <code>resize(...)</code></li><li>是否需要根据交互习惯调整样式和 tooltip 展示</li></ul>',27)])])}const m=a(d,[["render",n]]);export{u as __pageData,m as default};
